"""
T2 Blog — Article Routes

Implement article CRUD and tag-binding routes.
Register as a Flask Blueprint named 'article_bp'.

Requirements:
- GET /articles -> List all articles
  Optional query params: tag (filter by tag name), tag_id (filter by tag ID)
  Response: {"status": "ok", "data": [{"id": int, "title": str, "body": str}, ...]}

- POST /articles -> Create article
  Request: {"title": str, "body": str}
  Response: {"status": "ok", "data": {"id": int, "title": str, "body": str}}
  Errors: 400 if title or body missing

- GET /articles/<id> -> Get single article
  Response: {"status": "ok", "data": {"id": int, "title": str, "body": str}}
  Errors: 404 if not found

- POST /articles/<id>/tags -> Bind tags to article
  Request: {"tag_ids": [int, ...]}
  Response: {"status": "ok", "data": {"message": "Tags bound"}}
  Errors: 404 if article not found, 400 if tag not found

- GET /articles/<id>/tags -> Get article's tags
  Response: {"status": "ok", "data": [{"id": int, "name": str}, ...]}
  Errors: 404 if article not found

- DELETE /articles/<id>/tags/<tag_id> -> Unbind tag from article
  Response: {"status": "ok", "data": {"message": "Tag unbound"}}
  Errors: 404 if article not found

IMPORTANT: This module works with models.py (Article, Tag, article_tags) and
routes_tag.py. Make sure field names and response formats are consistent.
"""

from flask import Blueprint, request, jsonify

article_bp = Blueprint('article_bp', __name__)


@article_bp.route('/articles', methods=['GET'])
def list_articles():
    """List all articles, optionally filtered by tag name or tag_id."""
    from models import Article, Tag
    from app import db

    tag_name = request.args.get('tag')
    tag_id = request.args.get('tag_id')

    query = Article.query

    if tag_name:
        tag = Tag.query.filter_by(name=tag_name).first()
        if tag:
            query = query.join(Article.tags).filter(Tag.id == tag.id)
        else:
            return jsonify({'status': 'ok', 'data': []})

    if tag_id:
        try:
            tag_id_int = int(tag_id)
        except (ValueError, TypeError):
            return jsonify({'status': 'ok', 'data': []})
        query = query.join(Article.tags).filter(Tag.id == tag_id_int)

    articles = query.all()
    data = [{'id': a.id, 'title': a.title, 'body': a.body} for a in articles]
    return jsonify({'status': 'ok', 'data': data})


@article_bp.route('/articles', methods=['POST'])
def create_article():
    """Create a new article."""
    from models import Article
    from app import db

    data = request.get_json(silent=True) or {}
    title = data.get('title')
    body = data.get('body')

    if not title or not body:
        return jsonify({'status': 'error', 'message': 'title and body are required'}), 400

    article = Article(title=title, body=body)
    db.session.add(article)
    db.session.commit()

    return jsonify({'status': 'ok', 'data': {'id': article.id, 'title': article.title, 'body': article.body}}), 201


@article_bp.route('/articles/<int:article_id>', methods=['GET'])
def get_article(article_id):
    """Get a single article by ID."""
    from models import Article

    article = Article.query.get(article_id)
    if not article:
        return jsonify({'status': 'error', 'message': 'Article not found'}), 404

    return jsonify({'status': 'ok', 'data': {'id': article.id, 'title': article.title, 'body': article.body}})


@article_bp.route('/articles/<int:article_id>/tags', methods=['POST'])
def bind_tags(article_id):
    """Bind tags to an article."""
    from models import Article, Tag
    from app import db

    article = Article.query.get(article_id)
    if not article:
        return jsonify({'status': 'error', 'message': 'Article not found'}), 404

    data = request.get_json(silent=True) or {}
    tag_ids = data.get('tag_ids', [])

    for tid in tag_ids:
        tag = Tag.query.get(tid)
        if not tag:
            return jsonify({'status': 'error', 'message': f'Tag {tid} not found'}), 400
        if tag not in article.tags:
            article.tags.append(tag)

    db.session.commit()
    return jsonify({'status': 'ok', 'data': {'message': 'Tags bound'}})


@article_bp.route('/articles/<int:article_id>/tags', methods=['GET'])
def get_article_tags(article_id):
    """Get all tags for an article."""
    from models import Article

    article = Article.query.get(article_id)
    if not article:
        return jsonify({'status': 'error', 'message': 'Article not found'}), 404

    data = [{'id': t.id, 'name': t.name} for t in article.tags]
    return jsonify({'status': 'ok', 'data': data})


@article_bp.route('/articles/<int:article_id>/tags/<int:tag_id>', methods=['DELETE'])
def unbind_tag(article_id, tag_id):
    """Unbind a tag from an article."""
    from models import Article, Tag
    from app import db

    article = Article.query.get(article_id)
    if not article:
        return jsonify({'status': 'error', 'message': 'Article not found'}), 404

    tag = Tag.query.get(tag_id)
    if tag and tag in article.tags:
        article.tags.remove(tag)
        db.session.commit()

    return jsonify({'status': 'ok', 'data': {'message': 'Tag unbound'}})

"""
T2 Blog — Tag Routes

Implement tag CRUD routes.
Register as a Flask Blueprint named 'tag_bp'.

Requirements:
- POST /tags -> Create tag
  Request: {"name": str}
  Response: {"status": "ok", "data": {"id": int, "name": str}}
  Errors: 400 if name missing/empty, 409 if name already exists

- GET /tags -> List all tags
  Response: {"status": "ok", "data": [{"id": int, "name": str}, ...]}

- PUT /tags/<id> -> Update tag name
  Request: {"name": str}
  Response: {"status": "ok", "data": {"id": int, "name": str}}
  Errors: 404 if not found, 400 if name missing, 409 if duplicate name

- DELETE /tags/<id> -> Delete tag (also removes all article-tag associations)
  Response: {"status": "ok", "data": {"message": "Tag deleted"}}
  Errors: 404 if not found

IMPORTANT: Deleting a tag should cascade and remove all article-tag bindings
in the article_tags association table. This is used by routes_article.py.
"""

from flask import Blueprint, request, jsonify

tag_bp = Blueprint('tag_bp', __name__)


@tag_bp.route('/tags', methods=['POST'])
def create_tag():
    """Create a new tag."""
    from models import Tag
    from app import db

    data = request.get_json(silent=True) or {}
    name = data.get('name')

    if not name or not name.strip():
        return jsonify({'status': 'error', 'message': 'name is required'}), 400

    existing = Tag.query.filter_by(name=name).first()
    if existing:
        return jsonify({'status': 'error', 'message': 'Tag already exists'}), 409

    tag = Tag(name=name)
    db.session.add(tag)
    db.session.commit()

    return jsonify({'status': 'ok', 'data': {'id': tag.id, 'name': tag.name}}), 201


@tag_bp.route('/tags', methods=['GET'])
def list_tags():
    """List all tags."""
    from models import Tag

    tags = Tag.query.all()
    data = [{'id': t.id, 'name': t.name} for t in tags]
    return jsonify({'status': 'ok', 'data': data})


@tag_bp.route('/tags/<int:tag_id>', methods=['PUT'])
def update_tag(tag_id):
    """Update a tag's name."""
    from models import Tag
    from app import db

    tag = Tag.query.get(tag_id)
    if not tag:
        return jsonify({'status': 'error', 'message': 'Tag not found'}), 404

    data = request.get_json(silent=True) or {}
    name = data.get('name')

    if not name or not name.strip():
        return jsonify({'status': 'error', 'message': 'name is required'}), 400

    existing = Tag.query.filter_by(name=name).first()
    if existing and existing.id != tag_id:
        return jsonify({'status': 'error', 'message': 'Tag name already exists'}), 409

    tag.name = name
    db.session.commit()

    return jsonify({'status': 'ok', 'data': {'id': tag.id, 'name': tag.name}})


@tag_bp.route('/tags/<int:tag_id>', methods=['DELETE'])
def delete_tag(tag_id):
    """Delete a tag and remove all article-tag associations."""
    from models import Tag
    from app import db

    tag = Tag.query.get(tag_id)
    if not tag:
        return jsonify({'status': 'error', 'message': 'Tag not found'}), 404

    db.session.delete(tag)
    db.session.commit()

    return jsonify({'status': 'ok', 'data': {'message': 'Tag deleted'}})
